const headers = $input.first().json.headers;
const secret = headers['x-curiel-secret'];
const body = $input.first().json.body;

if (secret !== $env.CURIEL_SECRET_TOKEN) {
  throw new Error('Invalid secret token');
}

if (!body || !body.evaluation) {
  throw new Error('Missing evaluation data');
}

const ev = body.evaluation;
if (!ev.evaluatedEmail || !ev.compositeScore || !ev.weekStart || !ev.weekEnd) {
  throw new Error('Missing required evaluation fields: evaluatedEmail, compositeScore, weekStart, weekEnd');
}

return [{ json: { ...body, validated: true } }];

const ev = $input.first().json.evaluation;
const score = parseFloat(ev.compositeScore);

let scoreColor = '#17324a';
let scoreLabel = 'Excelente';
let scoreEmoji = '\u{1F31F}';

if (score < 4) {
  scoreColor = '#dc2626';
  scoreLabel = 'Requiere mejora';
  scoreEmoji = '\u{26A0}\u{FE0F}';
} else if (score < 6) {
  scoreColor = '#d97706';
  scoreLabel = 'Aceptable';
  scoreEmoji = '\u{1F4A1}';
} else if (score < 8) {
  scoreColor = '#2563eb';
  scoreLabel = 'Buen desempeno';
  scoreEmoji = '\u{1F4AA}';
}

const detailRows = (ev.details || []).map(d => {
  const val = parseFloat(d.score);
  const max = parseFloat(d.maxScore) || 10;
  const pct = Math.round((val / max) * 100);
  let barColor = '#17324a';
  if (pct < 40) barColor = '#dc2626';
  else if (pct < 70) barColor = '#d97706';
  else if (pct >= 80) barColor = '#16a34a';
  return '<tr><td style="padding:10px 12px;border-bottom:1px solid #f3f4f6;color:#374151;font-size:14px">' + (d.category || 'Sin categoria') + '</td><td style="padding:10px 12px;border-bottom:1px solid #f3f4f6;text-align:center;font-weight:600;color:#374151;font-size:14px">' + val + '/' + max + '</td><td style="padding:10px 12px;border-bottom:1px solid #f3f4f6;width:40%"><div style="background:#e5e7eb;border-radius:6px;height:8px;overflow:hidden"><div style="background:' + barColor + ';width:' + pct + '%;height:8px;border-radius:6px"></div></div></td></tr>';
}).join('');

return [{ json: { ...$input.first().json, scoreColor, scoreLabel, scoreEmoji, detailRows } }];
